async function loadRepairs(page=1){const f=state.filters;let url=`/api/repairs?page=${page}&limit=15`;if(f.status)url+=`&status=${f.status}`;if(f.search)url+=`&search=${encodeURIComponent(f.search)}`;if(f.date_from)url+=`&date_from=${f.date_from}`;if(f.date_to)url+=`&date_to=${f.date_to}`;const r=await api(url);if(r.ok){state.repairs={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0};}render();}
function renderRepairs(){const{data,page,total}=state.repairs;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Repairs</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewRepairModal()">+ New Repair</button></div></div><div class="filter-bar"><select onchange="state.filters.status=this.value;loadRepairs()"><option value="">All Status</option>${STATUSES.map(s=>`<option value="${s}"${state.filters.status===s?' selected':''}>${s.replace('_',' ')}</option>`).join('')}</select><input type="text" placeholder="Search model or customer..." value="${esc(state.filters.search||'')}" onkeyup="if(event.key==='Enter'){state.filters.search=this.value;loadRepairs()}"><input type="date" value="${state.filters.date_from||''}" onchange="state.filters.date_from=this.value;loadRepairs()"><input type="date" value="${state.filters.date_to||''}" onchange="state.filters.date_to=this.value;loadRepairs()"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadRepairs()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Customer</th><th>Model</th><th>Issues</th><th>Status</th><th>Assigned</th><th>Date</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(r=>`<tr><td>#${r.id}</td><td>${esc(r.customer_name||'-')}</td><td>${esc(r.model||'-')}</td><td style="max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${esc(r.issues||'-')}</td><td><span class="badge ${STATUS_COLORS[r.status]||''}">${(r.status||'').replace('_',' ')}</span></td><td>${esc(r.assigned_user_name||'-')}</td><td>${formatDate(r.created_at)}</td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showRepairDetail(${r.id})">View</button><select class="btn btn-ghost btn-sm" onchange="updateRepairStatus(${r.id},this.value)" style="padding:4px 8px;font-size:11px"><option value="">Status</option>${STATUSES.map(s=>`<option value="${s}">${s.replace('_',' ')}</option>`).join('')}</select></div></td></tr>`).join(''):'<tr><td colspan="8" class="empty">No repairs found</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadRepairs(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadRepairs(${page+1})">Next</button></div>`;}
async function updateRepairStatus(id,status){if(!status)return;const r=await api(`/api/repairs/${id}/status`,{method:'PATCH',body:JSON.stringify({status})});if(r.ok){toast('Status updated','success');loadRepairs(state.repairs.page);}else toast(r.data.error||'Failed to update status','error');}
async function showRepairDetail(id){const r=await api(`/api/repairs/${id}`);if(!r.ok)return toast('Failed to load repair','error');const rp=r.data;const parts=rp.parts_used||rp.parts||[];const pays=rp.payments||[];const totalParts=rp.total_parts_cost||parts.reduce((s,p)=>s+Number(p.selling_price||0)*Number(p.qty||1),0);const totalPaid=rp.total_payments||pays.reduce((s,p)=>s+Number(p.amount||0),0);const serviceFee=Number(rp.service_fee||0);const grandTotal=totalParts+serviceFee;const balance=rp.balance!==undefined?rp.balance:grandTotal-totalPaid;const canCancel=['received','diagnosed','waiting_parts','repairing'].includes(rp.status);const isAdmin=state.user&&(state.user.role==='admin'||state.user.role==='manager');
showModal(`<div class="modal-header"><h2>Repair #${rp.id}</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><div class="detail-grid"><div class="detail-item"><div class="label">Customer</div><div class="value">${esc(rp.customer_name||'-')}</div></div><div class="detail-item"><div class="label">Model</div><div class="value">${esc(rp.model||'-')}</div></div><div class="detail-item"><div class="label">IMEI</div><div class="value">${esc(rp.imei||'-')}</div></div><div class="detail-item"><div class="label">Status</div><div class="value"><span class="badge ${STATUS_COLORS[rp.status]||''}">${(rp.status||'').replace('_',' ')}</span></div></div><div class="detail-item"><div class="label">Assigned To</div><div class="value">${esc(rp.assigned_user_name||'Unassigned')}</div></div><div class="detail-item"><div class="label">Date</div><div class="value">${formatDateTime(rp.created_at)}</div></div><div class="detail-item detail-full"><div class="label">Issues</div><div class="value">${esc(rp.issues||'-')}</div></div><div class="detail-item detail-full"><div class="label">Notes</div><div class="value">${esc(rp.notes||'-')}</div></div></div>
<div style="margin-top:20px"><div class="card-header"><h3>Parts Used</h3><button class="btn btn-ghost btn-sm" onclick="showAddPartUsedModal(${rp.id})">+ Add Part</button></div><table><thead><tr><th>Part</th><th>Qty</th><th>Selling Price</th><th>Returned</th><th>Action</th></tr></thead><tbody>${parts.length?parts.map(p=>{const returned=Number(p.returned_qty||0);const canReturn=returned<Number(p.qty||0);return`<tr><td>${esc(p.name||p.part_name||'-')}</td><td>${p.qty||1}</td><td>${formatCurrency(p.selling_price)}</td><td>${returned>0?`<span class="badge badge-ok">${returned} returned</span>`:'-'}</td><td><div style="display:flex;gap:6px">${canReturn?`<button class="btn btn-warning btn-sm" onclick="returnPart(${rp.id},${p.id},${Number(p.qty||0)-returned})">Return</button>`:''}<button class="btn btn-danger btn-sm" onclick="removePartUsed(${rp.id},${p.id})">Remove</button></div></td></tr>`;}).join(''):'<tr><td colspan="5" class="empty">No parts added</td></tr>'}</tbody></table></div>
<div style="margin-top:20px"><div class="card-header"><h3>Payments</h3><button class="btn btn-ghost btn-sm" onclick="showAddPaymentModal(${rp.id})">+ Add Payment</button></div><table><thead><tr><th>Amount</th><th>Method</th><th>Date</th><th>Actions</th></tr></thead><tbody>${pays.length?pays.map(p=>`<tr><td>${formatCurrency(p.amount,p.currency)}</td><td>${esc(p.method||'-')}</td><td>${formatDate(p.created_at||p.date)}</td><td><div style="display:flex;gap:6px"><button class="btn btn-warning btn-sm" onclick="refundPayment(${rp.id},${p.id},${p.amount})">Refund</button><button class="btn btn-danger btn-sm" onclick="deletePayment(${p.id})">Delete</button></div></td></tr>`).join(''):'<tr><td colspan="4" class="empty">No payments recorded</td></tr>'}</tbody></table></div>
<div style="margin-top:16px;padding:16px;background:var(--bg);border-radius:8px"><div style="display:flex;justify-content:space-between;margin-bottom:8px"><span style="color:var(--text-muted)">Parts Total:</span><span>${formatCurrency(totalParts)}</span></div><div style="display:flex;justify-content:space-between;margin-bottom:8px"><span style="color:var(--text-muted)">Service Fee:</span><span>${rp.status!=='delivered'?`<input type="number" step="0.01" value="${serviceFee}" id="editServiceFee" style="width:120px;padding:4px 8px;background:var(--card);border:1px solid var(--border);border-radius:4px;color:var(--text);font-size:13px" onchange="updateServiceFee(${rp.id},this.value)">`:formatCurrency(serviceFee)}</span></div><div style="display:flex;justify-content:space-between;margin-bottom:8px;font-weight:600"><span>Grand Total:</span><span>${formatCurrency(grandTotal)}</span></div><div style="display:flex;justify-content:space-between;margin-bottom:8px"><span style="color:var(--text-muted)">Total Paid:</span><span style="color:var(--success)">${formatCurrency(totalPaid)}</span></div><div style="display:flex;justify-content:space-between;font-weight:700"><span>Balance Due:</span><span style="color:${balance>0?'var(--danger)':'var(--success)'}">${formatCurrency(balance)}</span></div></div>
<div style="margin-top:20px;display:flex;gap:8px;flex-wrap:wrap">${rp.status!=='delivered'?`<button class="btn btn-primary" onclick="advanceRepairStatus(${rp.id},'${rp.status}')">Advance Status</button>`:''}${canCancel&&isAdmin?`<button class="btn btn-danger" onclick="cancelRepair(${rp.id})">Cancel Repair</button>`:''}<button class="btn btn-ghost" onclick="hideModal()">Close</button></div></div>`);}
async function advanceRepairStatus(id,currentStatus){const idx=STATUSES.indexOf(currentStatus);if(idx>=STATUSES.length-1)return toast('Already at final status','info');const next=STATUSES[idx+1];const r=await api(`/api/repairs/${id}/status`,{method:'PATCH',body:JSON.stringify({status:next})});if(r.ok){toast(`Status updated to ${next}`,'success');hideModal();loadRepairs(state.repairs.page);}else toast(r.data.error||'Failed','error');}
async function cancelRepair(id){if(!confirm('Cancel this repair? This action cannot be undone.'))return;const r=await api(`/api/repairs/${id}/cancel`,{method:'POST'});if(r.ok){toast('Repair cancelled','success');hideModal();loadRepairs(state.repairs.page);}else toast(r.data.error||'Failed to cancel repair','error');}
async function updateServiceFee(repairId,val){const r=await api(`/api/repairs/${repairId}`,{method:'PUT',body:JSON.stringify({service_fee:parseFloat(val)||0})});if(r.ok){toast('Service fee updated','success');showRepairDetail(repairId);}else toast(r.data.error||'Failed','error');}
async function returnPart(repairId,rpId,maxQty){showModal(`<div class="modal-header"><h2>Return Part</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="doReturnPart(event,${repairId},${rpId})"><div class="form-group"><label>Quantity to Return (max ${maxQty})</label><input type="number" id="returnQty" min="1" max="${maxQty}" value="${maxQty}" required></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-warning">Return</button></div></form></div>`);}
async function doReturnPart(e,repairId,rpId){e.preventDefault();const qty=document.getElementById('returnQty').value;const r=await api(`/api/repairs/${repairId}/parts/${rpId}/return?qty=${qty}`,{method:'POST'});if(r.ok){toast('Part returned','success');showRepairDetail(repairId);loadRepairs(state.repairs.page);}else toast(r.data.error||'Failed to return part','error');}
async function refundPayment(repairId,paymentId,amount){if(!confirm(`Refund ${formatCurrency(amount)}?`))return;const r=await api('/api/payments',{method:'POST',body:JSON.stringify({repair_id:repairId,amount:-Math.abs(Number(amount)),currency:state.settings.default_currency,method:'Cash',notes:'Refund for payment #'+paymentId})});if(r.ok){toast('Refund recorded','success');showRepairDetail(repairId);}else toast(r.data.error||'Failed','error');}
async function removePartUsed(repairId,partId){if(!confirm('Remove this part?'))return;const r=await api(`/api/repairs/${repairId}/parts/${partId}`,{method:'DELETE'});if(r.ok){toast('Part removed','success');showRepairDetail(repairId);loadRepairs(state.repairs.page);}else toast(r.data.error||'Failed','error');}
async function deletePayment(id){if(!confirm('Delete this payment?'))return;const r=await api(`/api/payments/${id}`,{method:'DELETE'});if(r.ok){toast('Payment deleted','success');hideModal();loadRepairs(state.repairs.page);}else toast(r.data.error||'Failed','error');}
async function showNewRepairModal(){const[customersRes,staffRes]=await Promise.all([api('/api/customers?limit=100'),api('/api/staff?limit=100')]);const customers=customersRes.ok?(customersRes.data.items||[]):[];const staff=staffRes.ok?(Array.isArray(staffRes.data)?staffRes.data:staffRes.data.items||[]):[];showModal(`<div class="modal-header"><h2>New Repair</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createRepair(event)"><div class="form-group"><label>Customer</label><select id="repairCustomer" required><option value="">Select customer</option>${customers.map(c=>`<option value="${c.id}">${esc(c.name)} - ${esc(c.phone||'')}</option>`).join('')}</select><button type="button" class="btn btn-ghost btn-sm" style="margin-top:6px" onclick="showQuickCustomerModal()">+ New Customer</button></div><div class="form-group"><label>Model *</label><input type="text" id="repairModel" required placeholder="e.g. iPhone 14 Pro"></div><div class="form-group"><label>Issues *</label><textarea id="repairIssues" required placeholder="Describe the problems"></textarea></div><div class="form-row"><div class="form-group"><label>IMEI</label><input type="text" id="repairImei" placeholder="Optional"></div><div class="form-group"><label>Estimated Cost</label><input type="number" step="0.01" id="repairCost" placeholder="0.00"></div></div><div class="form-row"><div class="form-group"><label>Service Fee</label><input type="number" step="0.01" id="repairServiceFee" placeholder="0.00"></div><div class="form-group"><label>Assign To</label><select id="repairAssigned"><option value="">Unassigned</option>${staff.map(s=>`<option value="${s.id}">${esc(s.name)}</option>`).join('')}</select></div></div><div class="form-group"><label>Notes</label><textarea id="repairNotes" placeholder="Optional notes"></textarea></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Create</button></div></form></div>`);}
async function createRepair(e){e.preventDefault();const r=await api('/api/repairs',{method:'POST',body:JSON.stringify({customer_id:document.getElementById('repairCustomer').value,model:document.getElementById('repairModel').value,issues:document.getElementById('repairIssues').value,imei:document.getElementById('repairImei').value||undefined,estimated_cost:document.getElementById('repairCost').value||undefined,service_fee:document.getElementById('repairServiceFee').value||undefined,assigned_to:document.getElementById('repairAssigned').value||undefined,notes:document.getElementById('repairNotes').value||undefined})});if(r.ok){toast('Repair created','success');hideModal();loadRepairs();}else toast(r.data.error||'Failed to create repair','error');}
async function showQuickCustomerModal(){showModal(`<div class="modal-header"><h2>New Customer</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="quickCreateCustomer(event)"><div class="form-group"><label>Name *</label><input type="text" id="qcName" required></div><div class="form-row"><div class="form-group"><label>Phone</label><input type="text" id="qcPhone"></div><div class="form-group"><label>Email</label><input type="email" id="qcEmail"></div></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Create</button></div></form></div>`);}
async function quickCreateCustomer(e){e.preventDefault();const r=await api('/api/customers',{method:'POST',body:JSON.stringify({name:document.getElementById('qcName').value,phone:document.getElementById('qcPhone').value||undefined,email:document.getElementById('qcEmail').value||undefined})});if(r.ok){toast('Customer created','success');hideModal();showNewRepairModal();}else toast(r.data.error||'Failed','error');}
async function showAddPartUsedModal(repairId){const r=await api('/api/parts?limit=100');const parts=r.ok?(r.data.items||[]):[];showModal(`<div class="modal-header"><h2>Add Part</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="addPartUsed(event,${repairId})"><div class="form-group"><label>Part *</label><select id="addPartId" required><option value="">Select part</option>${parts.map(p=>`<option value="${p.id}">${esc(p.name)} (${esc(p.model||'any')}) - Stock: ${p.stock_qty} - Price: ${formatCurrency(p.selling_price)}</option>`).join('')}</select></div><div class="form-row"><div class="form-group"><label>Quantity</label><input type="number" id="addPartQty" value="1" min="1"></div><div class="form-group"><label>Selling Price</label><input type="number" step="0.01" id="addPartSellingPrice" placeholder="0.00"></div></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Add</button></div></form></div>`);}
async function addPartUsed(e,repairId){e.preventDefault();const partId=document.getElementById('addPartId').value;const qty=document.getElementById('addPartQty').value;const sellingPrice=document.getElementById('addPartSellingPrice').value||0;const r=await api(`/api/repairs/${repairId}/parts?part_id=${partId}&qty=${qty}&selling_price=${sellingPrice}`,{method:'POST'});if(r.ok){toast('Part added','success');hideModal();showRepairDetail(repairId);loadRepairs(state.repairs.page);}else toast(r.data.error||'Failed','error');}
async function showAddPaymentModal(repairId){showModal(`<div class="modal-header"><h2>Add Payment</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="addPayment(event,${repairId})"><div class="form-row"><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="payAmount" required></div><div class="form-group"><label>Currency</label><select id="payCurrency">${CURRENCIES.map(c=>`<option value="${c}"${c===state.settings.default_currency?' selected':''}>${c}</option>`).join('')}</select></div></div><div class="form-group"><label>Method *</label><select id="payMethod" required><option value="">Select method</option>${PAYMENT_METHODS.map(m=>`<option value="${m}">${m}</option>`).join('')}</select></div><div class="form-group"><label>Notes</label><input type="text" id="payNotes" placeholder="Optional"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Record Payment</button></div></form></div>`);}
async function addPayment(e,repairId){e.preventDefault();const r=await api('/api/payments',{method:'POST',body:JSON.stringify({repair_id:repairId,amount:document.getElementById('payAmount').value,currency:document.getElementById('payCurrency').value,method:document.getElementById('payMethod').value,notes:document.getElementById('payNotes').value||undefined})});if(r.ok){toast('Payment recorded','success');hideModal();showRepairDetail(repairId);loadRepairs(state.repairs.page);}else toast(r.data.error||'Failed','error');}
async function loadCustomers(page=1){const f=state.filters;let url=`/api/customers?page=${page}&limit=15`;if(f.search)url+=`&search=${encodeURIComponent(f.search)}`;const r=await api(url);if(r.ok){state.customers={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0};}render();}
function renderCustomers(){const{data,page,total}=state.customers;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Customers</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewCustomerModal()">+ New Customer</button></div></div><div class="filter-bar"><input type="text" placeholder="Search name or phone..." value="${esc(state.filters.search||'')}" onkeyup="if(event.key==='Enter'){state.filters.search=this.value;loadCustomers()}"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadCustomers()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Name</th><th>Phone</th><th>Email</th><th>Repairs</th><th>Created</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(c=>`<tr><td>#${c.id}</td><td>${esc(c.name)}</td><td>${esc(c.phone||'-')}</td><td>${esc(c.email||'-')}</td><td>${c.repairs_count||c.repair_count||0}</td><td>${formatDate(c.created_at)}</td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showCustomerDetail(${c.id})">History</button><button class="btn btn-ghost btn-sm" onclick="showEditCustomerModal(${c.id})">Edit</button><button class="btn btn-danger btn-sm" onclick="deleteCustomer(${c.id})">Delete</button></div></td></tr>`).join(''):'<tr><td colspan="7" class="empty">No customers found</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadCustomers(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadCustomers(${page+1})">Next</button></div>`;}
async function showNewCustomerModal(){showModal(`<div class="modal-header"><h2>New Customer</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createCustomer(event)"><div class="form-group"><label>Name *</label><input type="text" id="custName" required></div><div class="form-row"><div class="form-group"><label>Phone</label><input type="text" id="custPhone"></div><div class="form-group"><label>Email</label><input type="email" id="custEmail"></div></div><div class="form-group"><label>Address</label><input type="text" id="custAddress"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Create</button></div></form></div>`);}
async function createCustomer(e){e.preventDefault();const r=await api('/api/customers',{method:'POST',body:JSON.stringify({name:document.getElementById('custName').value,phone:document.getElementById('custPhone').value||undefined,email:document.getElementById('custEmail').value||undefined,address:document.getElementById('custAddress').value||undefined})});if(r.ok){toast('Customer created','success');hideModal();loadCustomers();}else toast(r.data.error||'Failed','error');}
async function showEditCustomerModal(id){const r=await api(`/api/customers/${id}`);if(!r.ok)return toast('Failed to load customer','error');const c=r.data;showModal(`<div class="modal-header"><h2>Edit Customer</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="updateCustomer(event,${id})"><div class="form-group"><label>Name *</label><input type="text" id="custName" value="${esc(c.name)}" required></div><div class="form-row"><div class="form-group"><label>Phone</label><input type="text" id="custPhone" value="${esc(c.phone||'')}"></div><div class="form-group"><label>Email</label><input type="email" id="custEmail" value="${esc(c.email||'')}"></div></div><div class="form-group"><label>Address</label><input type="text" id="custAddress" value="${esc(c.address||'')}"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Update</button></div></form></div>`);}
async function updateCustomer(e,id){e.preventDefault();const r=await api(`/api/customers/${id}`,{method:'PUT',body:JSON.stringify({name:document.getElementById('custName').value,phone:document.getElementById('custPhone').value||undefined,email:document.getElementById('custEmail').value||undefined,address:document.getElementById('custAddress').value||undefined})});if(r.ok){toast('Customer updated','success');hideModal();loadCustomers(state.customers.page);}else toast(r.data.error||'Failed','error');}
async function deleteCustomer(id){if(!confirm('Delete this customer?'))return;const r=await api(`/api/customers/${id}`,{method:'DELETE'});if(r.ok){toast('Customer deleted','success');loadCustomers(state.customers.page);}else toast(r.data.error||'Failed','error');}
async function showCustomerDetail(id){const r=await api(`/api/customers/${id}`);if(!r.ok)return toast('Failed','error');const c=r.data;const repairs=c.repairs||[];showModal(`<div class="modal-header"><h2>${esc(c.name)}</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><div class="detail-grid"><div class="detail-item"><div class="label">Phone</div><div class="value">${esc(c.phone||'-')}</div></div><div class="detail-item"><div class="label">Email</div><div class="value">${esc(c.email||'-')}</div></div><div class="detail-item detail-full"><div class="label">Address</div><div class="value">${esc(c.address||'-')}</div></div></div><h3 style="margin:20px 0 12px;font-size:16px">Repair History</h3><table><thead><tr><th>ID</th><th>Model</th><th>Status</th><th>Cost</th><th>Date</th></tr></thead><tbody>${repairs.length?repairs.map(rp=>`<tr><td>#${rp.id}</td><td>${esc(rp.model||'-')}</td><td><span class="badge ${STATUS_COLORS[rp.status]||''}">${(rp.status||'').replace('_',' ')}</span></td><td>${formatCurrency(rp.estimated_cost||rp.total_cost)}</td><td>${formatDate(rp.created_at)}</td></tr>`).join(''):'<tr><td colspan="5" class="empty">No repairs</td></tr>'}</tbody></table></div>`);}
async function loadParts(page=1){const f=state.filters;let url=`/api/parts?page=${page}&limit=15`;if(f.search)url+=`&search=${encodeURIComponent(f.search)}`;const r=await api(url);if(r.ok){state.parts={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0};}render();}
function renderParts(){const{data,page,total}=state.parts;const pages=Math.ceil(total/15)||1;const lowStock=data.filter(p=>p.stock_qty<=p.min_stock_alert);return`<div class="topbar"><h1>Inventory</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewPartModal()">+ Add Part</button></div></div>${lowStock.length?`<div style="background:rgba(239,68,68,.1);border:1px solid rgba(239,68,68,.3);border-radius:8px;padding:12px 16px;margin-bottom:16px;color:var(--danger);font-size:13px">&#9888; ${lowStock.length} part(s) below minimum stock level</div>`:''}<div class="filter-bar"><input type="text" placeholder="Search by name or model..." value="${esc(state.filters.search||'')}" onkeyup="if(event.key==='Enter'){state.filters.search=this.value;loadParts()}"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadParts()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>SKU</th><th>Name</th><th>Model</th><th>Brand</th><th>Stock</th><th>Unit Price</th><th>Sell Price</th><th>Status</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(p=>{const brandName=p.brand_name||(p.brand?p.brand.name:'')||'-';return`<tr><td>#${p.id}</td><td>${esc(p.sku||'-')}</td><td>${esc(p.name)}</td><td>${esc(p.model||'-')}</td><td>${esc(brandName)}</td><td>${p.stock_qty}</td><td>${formatCurrency(p.unit_price,p.currency)}</td><td>${formatCurrency(p.selling_price,p.currency)}</td><td><span class="badge ${p.stock_qty<=p.min_stock_alert?'badge-low':'badge-ok'}">${p.stock_qty<=p.min_stock_alert?'LOW STOCK':'OK'}</span></td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showEditPartModal(${p.id})">Edit</button><button class="btn btn-danger btn-sm" onclick="deletePart(${p.id})">Delete</button></div></td></tr>`}).join(''):'<tr><td colspan="10" class="empty">No parts found</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadParts(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadParts(${page+1})">Next</button></div>`;}
async function loadCatalogForParts(){const[brandsRes,catsRes,typesRes]=await Promise.all([api('/api/catalog/brands'),api('/api/catalog/categories'),api('/api/catalog/types')]);state.catalog.brands=brandsRes.ok?(Array.isArray(brandsRes.data)?brandsRes.data:[]):[];state.catalog.categories=catsRes.ok?(Array.isArray(catsRes.data)?catsRes.data:[]):[];state.catalog.types=typesRes.ok?(Array.isArray(typesRes.data)?typesRes.data:[]):[];}
function generateSKU(){return'PRT-'+Date.now().toString(36).toUpperCase()+'-'+Math.random().toString(36).substr(2,4).toUpperCase();}
function partFormHtml(prefix){const b=state.catalog.brands;const types=state.catalog.types;let typeOpts='';const grouped={};types.forEach(t=>{const catName=(state.catalog.categories.find(c=>c.id===t.category_id)||{}).name||'Uncategorized';if(!grouped[catName])grouped[catName]=[];grouped[catName].push(t);});Object.keys(grouped).forEach(cat=>{typeOpts+=`<optgroup label="${esc(cat)}">`;grouped[cat].forEach(t=>{typeOpts+=`<option value="${t.id}">${esc(t.name)}</option>`;});typeOpts+=`</optgroup>`;});return`<div class="form-row"><div class="form-group"><label>SKU</label><input type="text" id="${prefix}Sku" placeholder="Auto-generated"></div><div class="form-group"><label>Supplier Barcode</label><input type="text" id="${prefix}Barcode" placeholder="Supplier barcode"></div></div><div class="form-row"><div class="form-group"><label>Name *</label><input type="text" id="${prefix}Name" required></div><div class="form-group"><label>Model</label><input type="text" id="${prefix}Model" placeholder="e.g. iPhone 14"></div></div><div class="form-row"><div class="form-group"><label>Brand</label><select id="${prefix}Brand" onchange="loadModelsForBrand(this.value,'${prefix}')"><option value="">Select brand</option>${b.map(br=>`<option value="${br.id}">${esc(br.name)}</option>`).join('')}</select></div><div class="form-group"><label>Brand Model</label><select id="${prefix}BrandModel"><option value="">Select model</option></select></div></div><div class="form-group"><label>Part Type</label><select id="${prefix}Type"><option value="">Select type</option>${typeOpts}</select></div><div class="form-row"><div class="form-group"><label>Stock *</label><input type="number" id="${prefix}Stock" required min="0"></div><div class="form-group"><label>Min Alert *</label><input type="number" id="${prefix}MinStock" required min="0" value="5"></div></div><div class="form-row"><div class="form-group"><label>Unit Cost *</label><input type="number" step="0.01" id="${prefix}Price" required></div><div class="form-group"><label>Sell Price</label><input type="number" step="0.01" id="${prefix}SellPrice"></div></div><div class="form-group"><label>Currency</label><select id="${prefix}Currency">${CURRENCIES.map(c=>`<option value="${c}"${c===state.settings.default_currency?' selected':''}>${c}</option>`).join('')}</select></div>`;}
async function loadModelsForBrand(brandId,prefix){const sel=document.getElementById(prefix+'BrandModel');if(!sel)return;sel.innerHTML='<option value="">Loading...</option>';if(!brandId){sel.innerHTML='<option value="">Select model</option>';return;}const r=await api(`/api/catalog/models?brand_id=${brandId}`);const models=r.ok?(Array.isArray(r.data)?r.data:[]):[];sel.innerHTML='<option value="">Select model</option>'+models.map(m=>`<option value="${m.id}">${esc(m.name)}</option>`).join('');}
async function showNewPartModal(){await loadCatalogForParts();showModal(`<div class="modal-header"><h2>Add Part</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createPart(event)">${partFormHtml('p_')}<div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Add Part</button></div></form></div>`);}
async function createPart(e){e.preventDefault();const sku=document.getElementById('p_Sku').value;const r=await api('/api/parts',{method:'POST',body:JSON.stringify({name:document.getElementById('p_Name').value,sku:sku||undefined,model:document.getElementById('p_Model').value||undefined,brand_id:document.getElementById('p_Brand').value||undefined,model_id:document.getElementById('p_BrandModel').value||undefined,part_type_id:document.getElementById('p_Type').value||undefined,supplier_barcode:document.getElementById('p_Barcode').value||undefined,stock_qty:parseInt(document.getElementById('p_Stock').value),min_stock_alert:parseInt(document.getElementById('p_MinStock').value),unit_price:parseFloat(document.getElementById('p_Price').value),selling_price:parseFloat(document.getElementById('p_SellPrice').value),currency:document.getElementById('p_Currency').value})});if(r.ok){toast('Part added','success');hideModal();loadParts();}else toast(r.data.error||'Failed','error');}
async function showEditPartModal(id){const r=await api(`/api/parts/${id}`);if(!r.ok)return toast('Failed','error');const p=r.data;await loadCatalogForParts();showModal(`<div class="modal-header"><h2>Edit Part</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="updatePart(event,${id})"><div class="form-row"><div class="form-group"><label>SKU</label><input type="text" id="p_Sku" value="${esc(p.sku||'')}"></div><div class="form-group"><label>Supplier Barcode</label><input type="text" id="p_Barcode" value="${esc(p.supplier_barcode||'')}"></div></div><div class="form-row"><div class="form-group"><label>Name *</label><input type="text" id="p_Name" value="${esc(p.name)}" required></div><div class="form-group"><label>Model</label><input type="text" id="p_Model" value="${esc(p.model||'')}"></div></div><div class="form-row"><div class="form-group"><label>Brand</label><select id="p_Brand" onchange="loadModelsForBrand(this.value,'p_')"><option value="">Select brand</option>${state.catalog.brands.map(br=>`<option value="${br.id}"${p.brand_id==br.id?' selected':''}>${esc(br.name)}</option>`).join('')}</select></div><div class="form-group"><label>Brand Model</label><select id="p_BrandModel"><option value="">Select model</option></select></div></div><div class="form-group"><label>Part Type</label><select id="p_Type"><option value="">Select type</option>${state.catalog.types.map(t=>{const catName=(state.catalog.categories.find(c=>c.id===t.category_id)||{}).name||'Uncategorized';return`<optgroup label="${esc(catName)}"><option value="${t.id}"${p.part_type_id==t.id?' selected':''}>${esc(t.name)}</option></optgroup>`;}).join('')}</select></div><div class="form-row"><div class="form-group"><label>Stock *</label><input type="number" id="p_Stock" value="${p.stock_qty}" required min="0"></div><div class="form-group"><label>Min Alert *</label><input type="number" id="p_MinStock" value="${p.min_stock_alert}" required min="0"></div></div><div class="form-row"><div class="form-group"><label>Unit Cost *</label><input type="number" step="0.01" id="p_Price" value="${p.unit_price}" required></div><div class="form-group"><label>Sell Price</label><input type="number" step="0.01" id="p_SellPrice" value="${p.selling_price}"></div></div><div class="form-group"><label>Currency</label><select id="p_Currency">${CURRENCIES.map(c=>`<option value="${c}"${c===p.currency?' selected':''}>${c}</option>`).join('')}</select></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Update</button></div></form></div>`);}
async function updatePart(e,id){e.preventDefault();const r=await api(`/api/parts/${id}`,{method:'PUT',body:JSON.stringify({name:document.getElementById('p_Name').value,sku:document.getElementById('p_Sku').value||undefined,model:document.getElementById('p_Model').value||undefined,brand_id:document.getElementById('p_Brand').value||undefined,model_id:document.getElementById('p_BrandModel').value||undefined,part_type_id:document.getElementById('p_Type').value||undefined,supplier_barcode:document.getElementById('p_Barcode').value||undefined,stock_qty:parseInt(document.getElementById('p_Stock').value),min_stock_alert:parseInt(document.getElementById('p_MinStock').value),unit_price:parseFloat(document.getElementById('p_Price').value),selling_price:parseFloat(document.getElementById('p_SellPrice').value),currency:document.getElementById('p_Currency').value})});if(r.ok){toast('Part updated','success');hideModal();loadParts(state.parts.page);}else toast(r.data.error||'Failed','error');}
async function deletePart(id){if(!confirm('Delete this part?'))return;const r=await api(`/api/parts/${id}`,{method:'DELETE'});if(r.ok){toast('Part deleted','success');loadParts(state.parts.page);}else toast(r.data.error||'Failed','error');}
async function loadServices(){const r=await api('/api/services');if(r.ok){state.services={data:Array.isArray(r.data)?r.data:r.data.items||[],page:1,total:(Array.isArray(r.data)?r.data.length:r.data.total)||0};}render();}
function renderServices(){const{data}=state.services;return`<div class="topbar"><h1>Services (Price List)</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewServiceModal()">+ Add Service</button></div></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Name</th><th>Description</th><th>Price</th><th>Currency</th><th>Active</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(s=>`<tr><td>#${s.id}</td><td>${esc(s.name)}</td><td style="max-width:250px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${esc(s.description||'-')}</td><td>${formatCurrency(s.default_price,s.currency)}</td><td>${s.currency||state.settings.default_currency}</td><td><span class="badge ${s.active!==false?'badge-active':'badge-inactive'}">${s.active!==false?'Yes':'No'}</span></td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showEditServiceModal(${s.id})">Edit</button><button class="btn btn-danger btn-sm" onclick="deleteService(${s.id})">Delete</button></div></td></tr>`).join(''):'<tr><td colspan="7" class="empty">No services found</td></tr>'}</tbody></table></div></div>`;}
async function showNewServiceModal(){showModal(`<div class="modal-header"><h2>Add Service</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createService(event)"><div class="form-group"><label>Name *</label><input type="text" id="svcName" required placeholder="e.g. Screen Replacement"></div><div class="form-group"><label>Description</label><textarea id="svcDesc" placeholder="Service description"></textarea></div><div class="form-row"><div class="form-group"><label>Default Price *</label><input type="number" step="0.01" id="svcPrice" required></div><div class="form-group"><label>Currency</label><select id="svcCurrency">${CURRENCIES.map(c=>`<option value="${c}"${c===state.settings.default_currency?' selected':''}>${c}</option>`).join('')}</select></div></div><div class="form-group"><label><input type="checkbox" id="svcActive" checked> Active</label></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Add Service</button></div></form></div>`);}
async function createService(e){e.preventDefault();const r=await api('/api/services',{method:'POST',body:JSON.stringify({name:document.getElementById('svcName').value,description:document.getElementById('svcDesc').value||'',default_price:parseFloat(document.getElementById('svcPrice').value)||0,currency:document.getElementById('svcCurrency').value})});if(r.ok){toast('Service added','success');hideModal();loadServices();}else toast(r.data.error||'Failed','error');}
async function showEditServiceModal(id){const r=await api(`/api/services/${id}`);if(!r.ok)return toast('Failed','error');const s=r.data;showModal(`<div class="modal-header"><h2>Edit Service</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="updateService(event,${id})"><div class="form-group"><label>Name *</label><input type="text" id="svcName" value="${esc(s.name)}" required></div><div class="form-group"><label>Description</label><textarea id="svcDesc">${esc(s.description||'')}</textarea></div><div class="form-row"><div class="form-group"><label>Default Price *</label><input type="number" step="0.01" id="svcPrice" value="${s.default_price}" required></div><div class="form-group"><label>Currency</label><select id="svcCurrency">${CURRENCIES.map(c=>`<option value="${c}"${c===s.currency?' selected':''}>${c}</option>`).join('')}</select></div></div><div class="form-group"><label><input type="checkbox" id="svcActive" ${s.active!==false?'checked':''}> Active</label></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Update</button></div></form></div>`);}
async function updateService(e,id){e.preventDefault();const r=await api(`/api/services/${id}`,{method:'PUT',body:JSON.stringify({name:document.getElementById('svcName').value,description:document.getElementById('svcDesc').value||'',default_price:parseFloat(document.getElementById('svcPrice').value)||0,currency:document.getElementById('svcCurrency').value,active:document.getElementById('svcActive').checked})});if(r.ok){toast('Service updated','success');hideModal();loadServices();}else toast(r.data.error||'Failed','error');}
async function deleteService(id){if(!confirm('Delete this service?'))return;const r=await api(`/api/services/${id}`,{method:'DELETE'});if(r.ok){toast('Service deleted','success');loadServices();}else toast(r.data.error||'Failed','error');}
async function loadPayments(page=1){const f=state.filters;let url=`/api/payments?page=${page}&limit=15`;if(f.date_from)url+=`&date_from=${f.date_from}`;if(f.date_to)url+=`&date_to=${f.date_to}`;if(f.method)url+=`&method=${f.method}`;if(f.search)url+=`&search=${encodeURIComponent(f.search)}`;const r=await api(url);if(r.ok){state.payments={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0,summary:r.data.summary||{}};}render();}
function renderPayments(){const{data,page,total,summary}=state.payments;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Payments</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewPaymentModal()">+ Record Payment</button></div></div>${summary?`<div class="stats-grid">${Object.entries(summary).map(([k,v])=>`<div class="stat-card blue"><div class="stat-label">${esc(k)}</div><div class="stat-value">${formatCurrency(v,k)}</div></div>`).join('')}</div>`:''}<div class="filter-bar"><input type="date" value="${state.filters.date_from||''}" onchange="state.filters.date_from=this.value;loadPayments()"><input type="date" value="${state.filters.date_to||''}" onchange="state.filters.date_to=this.value;loadPayments()"><select onchange="state.filters.method=this.value;loadPayments()"><option value="">All Methods</option>${PAYMENT_METHODS.map(m=>`<option value="${m}"${state.filters.method===m?' selected':''}>${m}</option>`).join('')}</select><input type="text" placeholder="Search customer..." value="${esc(state.filters.search||'')}" onkeyup="if(event.key==='Enter'){state.filters.search=this.value;loadPayments()}"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadPayments()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Repair#</th><th>Customer</th><th>Amount</th><th>Method</th><th>Date</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(p=>`<tr><td>#${p.id}</td><td>${p.repair_id?'#'+p.repair_id:'-'}</td><td>${esc(p.customer_name||'-')}</td><td>${formatCurrency(p.amount,p.currency)}</td><td>${esc(p.method||'-')}</td><td>${formatDate(p.created_at||p.date)}</td><td><button class="btn btn-danger btn-sm" onclick="deletePaymentFromList(${p.id})">Delete</button></td></tr>`).join(''):'<tr><td colspan="7" class="empty">No payments found</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadPayments(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadPayments(${page+1})">Next</button></div>`;}
async function showNewPaymentModal(){const r=await api('/api/repairs?limit=100&status=received,diagnosed,waiting_parts,repairing,testing');const repairs=r.ok?(r.data.items||[]):[];showModal(`<div class="modal-header"><h2>Record Payment</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createPayment(event)"><div class="form-group"><label>Repair *</label><select id="payRepair" required><option value="">Select repair</option>${repairs.map(rp=>`<option value="${rp.id}">#${rp.id} - ${esc(rp.customer_name||'')} (${esc(rp.model||'')})</option>`).join('')}</select></div><div class="form-row"><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="payAmt" required></div><div class="form-group"><label>Currency</label><select id="payCur">${CURRENCIES.map(c=>`<option value="${c}"${c===state.settings.default_currency?' selected':''}>${c}</option>`).join('')}</select></div></div><div class="form-group"><label>Method *</label><select id="payMeth" required><option value="">Select method</option>${PAYMENT_METHODS.map(m=>`<option value="${m}">${m}</option>`).join('')}</select></div><div class="form-group"><label>Notes</label><input type="text" id="payNote"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Record</button></div></form></div>`);}
async function createPayment(e){e.preventDefault();const r=await api('/api/payments',{method:'POST',body:JSON.stringify({repair_id:document.getElementById('payRepair').value,amount:document.getElementById('payAmt').value,currency:document.getElementById('payCur').value,method:document.getElementById('payMeth').value,notes:document.getElementById('payNote').value||undefined})});if(r.ok){toast('Payment recorded','success');hideModal();loadPayments();}else toast(r.data.error||'Failed','error');}
async function deletePaymentFromList(id){if(!confirm('Delete this payment?'))return;const r=await api(`/api/payments/${id}`,{method:'DELETE'});if(r.ok){toast('Payment deleted','success');loadPayments(state.payments.page);}else toast(r.data.error||'Failed','error');}
async function loadExpenses(page=1){const f=state.filters;let url=`/api/expenses?page=${page}&limit=15`;if(f.date_from)url+=`&date_from=${f.date_from}`;if(f.date_to)url+=`&date_to=${f.date_to}`;if(f.category_id)url+=`&category_id=${f.category_id}`;const[r,catRes]=await Promise.all([api(url),api('/api/expenses/categories')]);if(r.ok){state.expenses={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0,monthly_total:r.data.monthly_total||0};}if(catRes.ok){state.expense_categories=Array.isArray(catRes.data)?catRes.data:[];}render();}
function renderExpenses(){const{data,page,total,monthly_total}=state.expenses;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Expenses</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewExpenseModal()">+ Add Expense</button></div></div><div class="stat-card red" style="margin-bottom:20px;max-width:300px"><div class="stat-label">This Month's Expenses</div><div class="stat-value">${formatCurrency(monthly_total)}</div></div><div class="filter-bar"><input type="date" value="${state.filters.date_from||''}" onchange="state.filters.date_from=this.value;loadExpenses()"><input type="date" value="${state.filters.date_to||''}" onchange="state.filters.date_to=this.value;loadExpenses()"><select onchange="state.filters.category_id=this.value;loadExpenses()"><option value="">All Categories</option>${(state.expense_categories||[]).map(c=>`<option value="${c.id}"${state.filters.category_id==c.id?' selected':''}>${esc(c.name)}</option>`).join('')}</select><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadExpenses()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Date</th><th>Category</th><th>Amount</th><th>Note</th><th>Created By</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(x=>`<tr><td>#${x.id}</td><td>${formatDate(x.date||x.created_at)}</td><td>${esc(x.category_name||'-')}</td><td>${formatCurrency(x.amount,x.currency)}</td><td>${esc(x.note||'-')}</td><td>${esc(x.created_by_name||x.user_name||'-')}</td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showEditExpenseModal(${x.id})">Edit</button><button class="btn btn-danger btn-sm" onclick="deleteExpense(${x.id})">Delete</button></div></td></tr>`).join(''):'<tr><td colspan="7" class="empty">No expenses found</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadExpenses(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadExpenses(${page+1})">Next</button></div>`;}
async function showNewExpenseModal(){if(!state.expense_categories.length){const catRes=await api('/api/expenses/categories');if(catRes.ok)state.expense_categories=Array.isArray(catRes.data)?catRes.data:[];}showModal(`<div class="modal-header"><h2>Add Expense</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createExpense(event)"><div class="form-row"><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="expAmt" required></div><div class="form-group"><label>Currency</label><select id="expCur">${CURRENCIES.map(c=>`<option value="${c}"${c===state.settings.default_currency?' selected':''}>${c}</option>`).join('')}</select></div></div><div class="form-group"><label>Category *</label><select id="expCat" required><option value="">Select category</option>${(state.expense_categories||[]).map(c=>`<option value="${c.id}">${esc(c.name)}</option>`).join('')}</select></div><div class="form-group"><label>Date</label><input type="date" id="expDate" value="${new Date().toISOString().split('T')[0]}"></div><div class="form-group"><label>Note</label><input type="text" id="expNote" placeholder="Description"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Add Expense</button></div></form></div>`);}
async function createExpense(e){e.preventDefault();const r=await api('/api/expenses',{method:'POST',body:JSON.stringify({amount:parseFloat(document.getElementById('expAmt').value),currency:document.getElementById('expCur').value,category_id:parseInt(document.getElementById('expCat').value),date:document.getElementById('expDate').value||undefined,note:document.getElementById('expNote').value||undefined})});if(r.ok){toast('Expense added','success');hideModal();loadExpenses();}else toast(r.data.detail||'Failed','error');}
async function showEditExpenseModal(id){const[r,catRes]=await Promise.all([api(`/api/expenses/${id}`),api('/api/expenses/categories')]);if(!r.ok)return toast('Failed','error');const x=r.data;const cats=catRes.ok?(Array.isArray(catRes.data)?catRes.data:[]):[];showModal(`<div class="modal-header"><h2>Edit Expense</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="updateExpense(event,${id})"><div class="form-row"><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="expAmt" value="${x.amount}" required></div><div class="form-group"><label>Currency</label><select id="expCur">${CURRENCIES.map(c=>`<option value="${c}"${c===x.currency?' selected':''}>${c}</option>`).join('')}</select></div></div><div class="form-group"><label>Category *</label><select id="expCat" required><option value="">Select</option>${cats.map(c=>`<option value="${c.id}"${c.id==x.category_id?' selected':''}>${esc(c.name)}</option>`).join('')}</select></div><div class="form-group"><label>Date</label><input type="date" id="expDate" value="${(x.date||x.created_at||'').split('T')[0]}"></div><div class="form-group"><label>Note</label><input type="text" id="expNote" value="${esc(x.note||'')}"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Update</button></div></form></div>`);}
async function updateExpense(e,id){e.preventDefault();const r=await api(`/api/expenses/${id}`,{method:'PUT',body:JSON.stringify({amount:parseFloat(document.getElementById('expAmt').value),currency:document.getElementById('expCur').value,category_id:parseInt(document.getElementById('expCat').value),date:document.getElementById('expDate').value||undefined,note:document.getElementById('expNote').value||undefined})});if(r.ok){toast('Expense updated','success');hideModal();loadExpenses(state.expenses.page);}else toast(r.data.error||'Failed','error');}
async function deleteExpense(id){if(!confirm('Delete this expense?'))return;const r=await api(`/api/expenses/${id}`,{method:'DELETE'});if(r.ok){toast('Expense deleted','success');loadExpenses(state.expenses.page);}else toast(r.data.error||'Failed','error');}
async function loadDailySales(page=1){const f=state.filters;let url=`/api/daily-sales?page=${page}&limit=15`;if(f.date_from)url+=`&date_from=${f.date_from}`;if(f.date_to)url+=`&date_to=${f.date_to}`;const r=await api(url);if(r.ok){state.daily_sales={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0,monthly_total:r.data.monthly_total||0};}render();}
function renderDailySales(){const{data,page,total,monthly_total}=state.daily_sales;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Daily Sales</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewDailySaleModal()">+ Add Entry</button></div></div><div class="stat-card green" style="margin-bottom:20px;max-width:300px"><div class="stat-label">This Month's Manual Sales</div><div class="stat-value">${formatCurrency(monthly_total)}</div></div><div class="filter-bar"><input type="date" value="${state.filters.date_from||''}" onchange="state.filters.date_from=this.value;loadDailySales()"><input type="date" value="${state.filters.date_to||''}" onchange="state.filters.date_to=this.value;loadDailySales()"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadDailySales()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Date</th><th>Amount</th><th>Category</th><th>Note</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(s=>`<tr><td>#${s.id}</td><td>${formatDate(s.date||s.created_at)}</td><td>${formatCurrency(s.amount,s.currency)}</td><td>${esc(s.category||'-')}</td><td>${esc(s.note||'-')}</td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showEditDailySaleModal(${s.id})">Edit</button><button class="btn btn-danger btn-sm" onclick="deleteDailySale(${s.id})">Delete</button></div></td></tr>`).join(''):'<tr><td colspan="6" class="empty">No sales entries found</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadDailySales(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadDailySales(${page+1})">Next</button></div>`;}
async function showNewDailySaleModal(){showModal(`<div class="modal-header"><h2>Add Sales Entry</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createDailySale(event)"><div class="form-row"><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="saleAmt" required></div><div class="form-group"><label>Currency</label><select id="saleCur">${CURRENCIES.map(c=>`<option value="${c}"${c===state.settings.default_currency?' selected':''}>${c}</option>`).join('')}</select></div></div><div class="form-group"><label>Category</label><input type="text" id="saleCat" placeholder="e.g. Parts, Accessories"></div><div class="form-group"><label>Date</label><input type="date" id="saleDate" value="${new Date().toISOString().split('T')[0]}"></div><div class="form-group"><label>Note</label><input type="text" id="saleNote" placeholder="Description"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Add Entry</button></div></form></div>`);}
async function createDailySale(e){e.preventDefault();const r=await api('/api/daily-sales',{method:'POST',body:JSON.stringify({amount:document.getElementById('saleAmt').value,currency:document.getElementById('saleCur').value,category:document.getElementById('saleCat').value||undefined,date:document.getElementById('saleDate').value||undefined,note:document.getElementById('saleNote').value||undefined})});if(r.ok){toast('Entry added','success');hideModal();loadDailySales();}else toast(r.data.error||'Failed','error');}
async function showEditDailySaleModal(id){const r=await api(`/api/daily-sales/${id}`);if(!r.ok)return toast('Failed','error');const s=r.data;showModal(`<div class="modal-header"><h2>Edit Sales Entry</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="updateDailySale(event,${id})"><div class="form-row"><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="saleAmt" value="${s.amount}" required></div><div class="form-group"><label>Currency</label><select id="saleCur">${CURRENCIES.map(c=>`<option value="${c}"${c===s.currency?' selected':''}>${c}</option>`).join('')}</select></div></div><div class="form-group"><label>Category</label><input type="text" id="saleCat" value="${esc(s.category||'')}"></div><div class="form-group"><label>Date</label><input type="date" id="saleDate" value="${(s.date||s.created_at||'').split('T')[0]}"></div><div class="form-group"><label>Note</label><input type="text" id="saleNote" value="${esc(s.note||'')}"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Update</button></div></form></div>`);}
async function updateDailySale(e,id){e.preventDefault();const r=await api(`/api/daily-sales/${id}`,{method:'PUT',body:JSON.stringify({amount:document.getElementById('saleAmt').value,currency:document.getElementById('saleCur').value,category:document.getElementById('saleCat').value||undefined,date:document.getElementById('saleDate').value||undefined,note:document.getElementById('saleNote').value||undefined})});if(r.ok){toast('Entry updated','success');hideModal();loadDailySales(state.daily_sales.page);}else toast(r.data.error||'Failed','error');}
async function deleteDailySale(id){if(!confirm('Delete this entry?'))return;const r=await api(`/api/daily-sales/${id}`,{method:'DELETE'});if(r.ok){toast('Entry deleted','success');loadDailySales(state.daily_sales.page);}else toast(r.data.error||'Failed','error');}
async function loadSuppliers(page=1){const f=state.filters;let url=`/api/suppliers?page=${page}&limit=15`;if(f.search)url+=`&search=${encodeURIComponent(f.search)}`;const r=await api(url);if(r.ok){state.suppliers={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0};}render();}
function renderSuppliers(){if(state.current_supplier_id)return renderSupplierDetail();const{data,page,total}=state.suppliers;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Suppliers</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewSupplierModal()">+ Add Supplier</button></div></div><div class="filter-bar"><input type="text" placeholder="Search supplier..." value="${esc(state.filters.search||'')}" onkeyup="if(event.key==='Enter'){state.filters.search=this.value;loadSuppliers()}"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadSuppliers()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Name</th><th>Phone</th><th>Email</th><th>Balance</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(s=>`<tr><td>#${s.id}</td><td>${esc(s.name)}</td><td>${esc(s.phone||'-')}</td><td>${esc(s.email||'-')}</td><td style="font-weight:600;color:${(s.balance||0)>0?'var(--danger)':'var(--success)'}">${formatCurrency(s.balance||0)}</td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="viewSupplier(${s.id})">View</button><button class="btn btn-ghost btn-sm" onclick="showEditSupplierModal(${s.id})">Edit</button><button class="btn btn-danger btn-sm" onclick="deleteSupplier(${s.id})">Delete</button></div></td></tr>`).join(''):'<tr><td colspan="6" class="empty">No suppliers found</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadSuppliers(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadSuppliers(${page+1})">Next</button></div>`;}
async function viewSupplier(id){state.current_supplier_id=id;state.current_po_id=null;render();}
async function showNewSupplierModal(){showModal(`<div class="modal-header"><h2>Add Supplier</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createSupplier(event)"><div class="form-group"><label>Name *</label><input type="text" id="supName" required></div><div class="form-row"><div class="form-group"><label>Phone</label><input type="text" id="supPhone"></div><div class="form-group"><label>Email</label><input type="email" id="supEmail"></div></div><div class="form-group"><label>Address</label><input type="text" id="supAddress"></div><div class="form-group"><label>Notes</label><textarea id="supNotes" placeholder="Optional notes"></textarea></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Create</button></div></form></div>`);}
async function createSupplier(e){e.preventDefault();const r=await api('/api/suppliers',{method:'POST',body:JSON.stringify({name:document.getElementById('supName').value,phone:document.getElementById('supPhone').value||undefined,email:document.getElementById('supEmail').value||undefined,address:document.getElementById('supAddress').value||undefined,notes:document.getElementById('supNotes').value||undefined})});if(r.ok){toast('Supplier created','success');hideModal();loadSuppliers();}else toast(r.data.error||'Failed','error');}
async function showEditSupplierModal(id){const r=await api(`/api/suppliers/${id}`);if(!r.ok)return toast('Failed','error');const s=r.data;showModal(`<div class="modal-header"><h2>Edit Supplier</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="updateSupplier(event,${id})"><div class="form-group"><label>Name *</label><input type="text" id="supName" value="${esc(s.name)}" required></div><div class="form-row"><div class="form-group"><label>Phone</label><input type="text" id="supPhone" value="${esc(s.phone||'')}"></div><div class="form-group"><label>Email</label><input type="email" id="supEmail" value="${esc(s.email||'')}"></div></div><div class="form-group"><label>Address</label><input type="text" id="supAddress" value="${esc(s.address||'')}"></div><div class="form-group"><label>Notes</label><textarea id="supNotes">${esc(s.notes||'')}</textarea></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Update</button></div></form></div>`);}
async function updateSupplier(e,id){e.preventDefault();const r=await api(`/api/suppliers/${id}`,{method:'PUT',body:JSON.stringify({name:document.getElementById('supName').value,phone:document.getElementById('supPhone').value||undefined,email:document.getElementById('supEmail').value||undefined,address:document.getElementById('supAddress').value||undefined,notes:document.getElementById('supNotes').value||undefined})});if(r.ok){toast('Supplier updated','success');hideModal();loadSuppliers(state.suppliers.page);}else toast(r.data.error||'Failed','error');}
async function deleteSupplier(id){if(!confirm('Delete this supplier?'))return;const r=await api(`/api/suppliers/${id}`,{method:'DELETE'});if(r.ok){toast('Supplier deleted','success');loadSuppliers(state.suppliers.page);}else toast(r.data.error||'Failed','error');}
async function renderSupplierDetail(){const id=state.current_supplier_id;const r=await api(`/api/suppliers/${id}`);if(!r.ok){state.current_supplier_id=null;return render();}const s=r.data;const purchases=s.purchases||[];const payments=s.payments||[];const totalPurchases=purchases.reduce((t,p)=>t+Number(p.total||p.amount||0),0);const totalPayments=payments.reduce((t,p)=>t+Number(p.amount||0),0);const balance=totalPurchases-totalPayments;
document.querySelector('.main').innerHTML=`<div class="topbar"><h1>Supplier: ${esc(s.name)}</h1><div class="topbar-actions"><button class="btn btn-ghost" onclick="state.current_supplier_id=null;loadSuppliers()">Back to List</button><button class="btn btn-primary" onclick="showRecordSupplierPaymentModal(${s.id})">Record Payment</button></div></div>
<div class="stats-grid"><div class="stat-card blue"><div class="stat-label">Total Purchases</div><div class="stat-value">${formatCurrency(totalPurchases)}</div></div><div class="stat-card green"><div class="stat-label">Total Paid</div><div class="stat-value">${formatCurrency(totalPayments)}</div></div><div class="stat-card red"><div class="stat-label">Balance Due</div><div class="stat-value">${formatCurrency(balance)}</div></div></div>
<div class="card"><div class="card-header"><h3>Contact Info</h3></div><div class="detail-grid"><div class="detail-item"><div class="label">Phone</div><div class="value">${esc(s.phone||'-')}</div></div><div class="detail-item"><div class="label">Email</div><div class="value">${esc(s.email||'-')}</div></div><div class="detail-item detail-full"><div class="label">Address</div><div class="value">${esc(s.address||'-')}</div></div><div class="detail-item detail-full"><div class="label">Notes</div><div class="value">${esc(s.notes||'-')}</div></div></div></div>
<div class="card"><div class="card-header"><h3>Purchase History</h3></div><table><thead><tr><th>ID</th><th>Date</th><th>Amount</th><th>Status</th></tr></thead><tbody>${purchases.length?purchases.map(p=>`<tr><td>#${p.id}</td><td>${formatDate(p.created_at||p.date)}</td><td>${formatCurrency(p.total||p.amount)}</td><td><span class="badge ${PO_STATUS_COLORS[p.status]||''}">${(p.status||'').replace('_',' ')}</span></td></tr>`).join(''):'<tr><td colspan="4" class="empty">No purchases</td></tr>'}</tbody></table></div>
<div class="card"><div class="card-header"><h3>Payments</h3></div><table><thead><tr><th>ID</th><th>Date</th><th>Amount</th><th>Method</th><th>Notes</th></tr></thead><tbody>${payments.length?payments.map(p=>`<tr><td>#${p.id}</td><td>${formatDate(p.created_at||p.date)}</td><td>${formatCurrency(p.amount)}</td><td>${esc(p.method||'-')}</td><td>${esc(p.notes||'-')}</td></tr>`).join(''):'<tr><td colspan="5" class="empty">No payments</td></tr>'}</tbody></table></div>`;}
async function showRecordSupplierPaymentModal(supId){showModal(`<div class="modal-header"><h2>Record Payment to Supplier</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createSupplierPayment(event,${supId})"><div class="form-row"><div class="form-group"><label>Amount *</label><input type="number" step="0.01" id="supPayAmt" required></div><div class="form-group"><label>Currency</label><select id="supPayCur">${CURRENCIES.map(c=>`<option value="${c}"${c===state.settings.default_currency?' selected':''}>${c}</option>`).join('')}</select></div></div><div class="form-group"><label>Method *</label><select id="supPayMeth" required><option value="">Select method</option>${PAYMENT_METHODS.map(m=>`<option value="${m}">${m}</option>`).join('')}</select></div><div class="form-group"><label>Notes</label><input type="text" id="supPayNotes" placeholder="Optional"></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Record Payment</button></div></form></div>`);}
async function createSupplierPayment(e,supId){e.preventDefault();const r=await api(`/api/suppliers/${supId}/payments`,{method:'POST',body:JSON.stringify({amount:parseFloat(document.getElementById('supPayAmt').value),currency:document.getElementById('supPayCur').value,method:document.getElementById('supPayMeth').value,notes:document.getElementById('supPayNotes').value||undefined})});if(r.ok){toast('Payment recorded','success');hideModal();renderSupplierDetail();}else toast(r.data.error||'Failed','error');}
async function loadPurchaseOrders(page=1){const f=state.filters;let url=`/api/purchase-orders?page=${page}&limit=15`;if(f.status)url+=`&status=${f.status}`;if(f.search)url+=`&search=${encodeURIComponent(f.search)}`;const r=await api(url);if(r.ok){state.purchase_orders={data:r.data.items||[],page:r.data.page||page,total:r.data.total||0};}render();}
function renderPurchaseOrders(){if(state.current_po_id)return renderPODetail();const{data,page,total}=state.purchase_orders;const pages=Math.ceil(total/15)||1;return`<div class="topbar"><h1>Purchase Orders</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewPOModal()">+ New PO</button></div></div><div class="filter-bar"><select onchange="state.filters.status=this.value;loadPurchaseOrders()"><option value="">All Status</option>${PO_STATUSES.map(s=>`<option value="${s}"${state.filters.status===s?' selected':''}>${s.replace('_',' ')}</option>`).join('')}</select><input type="text" placeholder="Search..." value="${esc(state.filters.search||'')}" onkeyup="if(event.key==='Enter'){state.filters.search=this.value;loadPurchaseOrders()}"><button class="btn btn-ghost btn-sm" onclick="state.filters={};loadPurchaseOrders()">Clear</button></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Supplier</th><th>Status</th><th>Items</th><th>Total</th><th>Date</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(po=>`<tr><td>#${po.id}</td><td>${esc(po.supplier_name||'-')}</td><td><span class="badge ${PO_STATUS_COLORS[po.status]||''}">${(po.status||'').replace('_',' ')}</span></td><td>${po.items_count||po.items?.length||0}</td><td>${formatCurrency(po.total)}</td><td>${formatDate(po.created_at)}</td><td><button class="btn btn-ghost btn-sm" onclick="viewPO(${po.id})">View</button></td></tr>`).join(''):'<tr><td colspan="7" class="empty">No purchase orders found</td></tr>'}</tbody></table></div></div><div class="pagination"><button ${page<=1?'disabled':''} onclick="loadPurchaseOrders(${page-1})">Prev</button><span style="color:var(--text-muted);font-size:13px">Page ${page} of ${pages}</span><button ${page>=pages?'disabled':''} onclick="loadPurchaseOrders(${page+1})">Next</button></div>`;}
function viewPO(id){state.current_po_id=id;state.current_supplier_id=null;render();}
let poItems=[];
function showNewPOModal(){poItems=[{part_name:'',qty:1,cost:0,selling_price:0}];showNewPOForm();}
async function showNewPOForm(){const supRes=await api('/api/suppliers?limit=100');const suppliers=supRes.ok?(supRes.data.items||[]):[];showModal(`<div class="modal-header"><h2>New Purchase Order</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createPO(event)"><div class="form-group"><label>Supplier *</label><select id="poSupplier" required><option value="">Select supplier</option>${suppliers.map(s=>`<option value="${s.id}">${esc(s.name)}</option>`).join('')}</select><button type="button" class="btn btn-ghost btn-sm" style="margin-top:6px" onclick="showNewSupplierModal()">+ New Supplier</button></div><div id="poItemsContainer"><div class="card-header"><h3>Items</h3><button type="button" class="btn btn-ghost btn-sm" onclick="addPOItem()">+ Add Item</button></div><div id="poItemList">${poItems.map((item,i)=>poItemRowHtml(i,item)).join('')}</div></div><div style="margin-top:12px;padding:12px;background:var(--bg);border-radius:8px"><strong>Total: </strong><span id="poTotal">${formatCurrency(poItems.reduce((s,it)=>s+Number(it.cost||0)*Number(it.qty||0),0))}</span></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Create PO</button></div></form></div>`);}
function poItemRowHtml(i,item){return`<div style="display:grid;grid-template-columns:2fr 1fr 1fr 1fr auto;gap:8px;margin-bottom:8px;align-items:end" id="poItem${i}"><div class="form-group" style="margin:0"><label style="font-size:11px">Part Name</label><input type="text" value="${esc(item.part_name||'')}" onchange="poItems[${i}].part_name=this.value" required></div><div class="form-group" style="margin:0"><label style="font-size:11px">Qty</label><input type="number" value="${item.qty||1}" min="1" onchange="poItems[${i}].qty=Number(this.value);updatePOTotal()" required></div><div class="form-group" style="margin:0"><label style="font-size:11px">Cost</label><input type="number" step="0.01" value="${item.cost||0}" onchange="poItems[${i}].cost=Number(this.value);updatePOTotal()" required></div><div class="form-group" style="margin:0"><label style="font-size:11px">Sell Price</label><input type="number" step="0.01" value="${item.selling_price||0}" onchange="poItems[${i}].selling_price=Number(this.value)" required></div><button type="button" class="btn btn-danger btn-sm" onclick="removePOItem(${i})" style="margin-top:18px">&#10005;</button></div>`;}
function addPOItem(){poItems.push({part_name:'',qty:1,cost:0,selling_price:0});document.getElementById('poItemList').innerHTML=poItems.map((item,i)=>poItemRowHtml(i,item)).join('');}
function removePOItem(i){poItems.splice(i,1);document.getElementById('poItemList').innerHTML=poItems.map((item,idx)=>poItemRowHtml(idx,item)).join('');updatePOTotal();}
function updatePOTotal(){const total=poItems.reduce((s,it)=>s+Number(it.cost||0)*Number(it.qty||0),0);const el=document.getElementById('poTotal');if(el)el.textContent=formatCurrency(total);}
async function createPO(e){e.preventDefault();const r=await api('/api/purchase-orders',{method:'POST',body:JSON.stringify({supplier_id:document.getElementById('poSupplier').value,items:poItems.filter(it=>it.part_name)})});if(r.ok){toast('PO created','success');hideModal();loadPurchaseOrders();}else toast(r.data.error||'Failed','error');}
async function renderPODetail(){const id=state.current_po_id;const r=await api(`/api/purchase-orders/${id}`);if(!r.ok){state.current_po_id=null;return render();}const po=r.data;const items=po.items||[];const receipts=po.receipts||[];const canSend=po.status==='draft';const canReceive=['draft','sent'].includes(po.status);const canCancel=['draft','sent'].includes(po.status);
document.querySelector('.main').innerHTML=`<div class="topbar"><h1>Purchase Order #${po.id}</h1><div class="topbar-actions"><button class="btn btn-ghost" onclick="state.current_po_id=null;loadPurchaseOrders()">Back to List</button></div></div>
<div class="stats-grid"><div class="stat-card blue"><div class="stat-label">Status</div><div class="stat-value" style="font-size:18px"><span class="badge ${PO_STATUS_COLORS[po.status]||''}">${(po.status||'').replace('_',' ')}</span></div></div><div class="stat-card green"><div class="stat-label">Supplier</div><div class="stat-value" style="font-size:18px">${esc(po.supplier_name||'-')}</div></div><div class="stat-card cyan"><div class="stat-label">Total</div><div class="stat-value">${formatCurrency(po.total)}</div></div><div class="stat-card yellow"><div class="stat-label">Created</div><div class="stat-value" style="font-size:16px">${formatDate(po.created_at)}</div></div></div>
<div class="card"><div class="card-header"><h3>Items</h3></div><table><thead><tr><th>Part</th><th>Qty Ordered</th><th>Cost</th><th>Sell Price</th><th>Subtotal</th></tr></thead><tbody>${items.length?items.map(it=>`<tr><td>${esc(it.part_name||'-')}</td><td>${it.qty}</td><td>${formatCurrency(it.cost)}</td><td>${formatCurrency(it.selling_price)}</td><td>${formatCurrency(Number(it.cost)*Number(it.qty))}</td></tr>`).join(''):'<tr><td colspan="5" class="empty">No items</td></tr>'}</tbody></table></div>
${receipts.length?`<div class="card"><div class="card-header"><h3>Receipts</h3></div><table><thead><tr><th>ID</th><th>Invoice #</th><th>Date</th><th>Items</th></tr></thead><tbody>${receipts.map(rc=>`<tr><td>#${rc.id}</td><td>${esc(rc.invoice_number||'-')}</td><td>${formatDate(rc.created_at)}</td><td>${(rc.items||[]).length} items</td></tr>`).join('')}</tbody></table></div>`:''}
<div style="margin-top:16px;display:flex;gap:8px;flex-wrap:wrap">
${canSend?`<button class="btn btn-primary" onclick="sendPO(${po.id})">Send to Supplier</button>`:''}
${canReceive?`<button class="btn btn-success" onclick="showReceiveShipmentModal(${po.id})">Receive Shipment</button>`:''}
${canCancel?`<button class="btn btn-danger" onclick="cancelPO(${po.id})">Cancel PO</button>`:''}
</div>`;}
async function sendPO(id){if(!confirm('Send this PO to supplier?'))return;const r=await api(`/api/purchase-orders/${id}/status`,{method:'PUT',body:JSON.stringify({status:'sent'})});if(r.ok){toast('PO sent to supplier','success');renderPODetail();}else toast(r.data.error||'Failed','error');}
async function cancelPO(id){if(!confirm('Cancel this PO?'))return;const r=await api(`/api/purchase-orders/${id}/status`,{method:'PUT',body:JSON.stringify({status:'cancelled'})});if(r.ok){toast('PO cancelled','success');state.current_po_id=null;loadPurchaseOrders();}else toast(r.data.error||'Failed','error');}
async function showReceiveShipmentModal(poId){const poRes=await api(`/api/purchase-orders/${poId}`);if(!poRes.ok)return toast('Failed to load PO','error');const po=poRes.data;const items=po.items||[];const receivedItems=items.map(it=>({...it,qty_received:it.qty,actual_cost:it.cost}));showModal(`<div class="modal-header"><h2>Receive Shipment - PO #${po.id}</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="submitReceive(event,${poId})"><div class="form-group"><label>Invoice Number *</label><input type="text" id="rcvInvoice" required placeholder="Enter supplier invoice number"></div><div style="margin-top:16px"><h3 style="font-size:14px;margin-bottom:12px">Match Items</h3><div style="display:grid;grid-template-columns:1fr 80px 80px 80px 80px;gap:8px;margin-bottom:8px;padding:0 12px"><span style="font-size:11px;color:var(--text-muted);font-weight:600">Part</span><span style="font-size:11px;color:var(--text-muted);font-weight:600;text-align:center">Ordered</span><span style="font-size:11px;color:var(--text-muted);font-weight:600;text-align:center">Received</span><span style="font-size:11px;color:var(--text-muted);font-weight:600;text-align:center">PO Cost</span><span style="font-size:11px;color:var(--text-muted);font-weight:600;text-align:center">Actual Cost</span></div>${items.map((it,idx)=>`<div style="display:grid;grid-template-columns:1fr 80px 80px 80px 80px;gap:8px;align-items:center;padding:8px 12px;background:var(--bg);border-radius:6px;margin-bottom:6px"><span style="font-size:13px">${esc(it.part_name||'-')}</span><span style="font-size:13px;text-align:center">${it.qty}</span><input type="number" class="rcvQty" data-idx="${idx}" value="${it.qty}" min="0" style="width:80px;padding:4px;text-align:center;background:var(--card);border:1px solid var(--border);border-radius:4px;color:var(--text);font-size:13px"><span style="font-size:13px;text-align:center">${formatCurrency(it.cost)}</span><input type="number" class="rcvCost" data-idx="${idx}" value="${it.cost}" step="0.01" style="width:80px;padding:4px;text-align:center;background:var(--card);border:1px solid var(--border);border-radius:4px;color:var(--text);font-size:13px"></div>`).join('')}</div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-success">Receive</button></div></form></div>`);}
async function submitReceive(e,poId){e.preventDefault();const invoiceNumber=document.getElementById('rcvInvoice').value;const qtyInputs=document.querySelectorAll('.rcvQty');const costInputs=document.querySelectorAll('.rcvCost');const items=[];qtyInputs.forEach((el,i)=>{items.push({po_item_id:Number(el.dataset.idx)+1,qty_received:Number(el.value),actual_cost:Number(costInputs[i].value)});});const r=await api(`/api/purchase-orders/${poId}/receive`,{method:'POST',body:JSON.stringify({invoice_number:invoiceNumber,items})});if(r.ok){toast('Shipment received','success');hideModal();renderPODetail();}else toast(r.data.error||'Failed to receive shipment','error');}
async function loadReports(){const f=state.filters;let url='/api/reports?';if(f.date_from)url+=`date_from=${f.date_from}&`;if(f.date_to)url+=`date_to=${f.date_to}&`;const r=await api(url);if(r.ok){state.reports=r.data;}render();}
function renderReports(){const d=state.reports||{};const daily=d.daily_summary||d.daily||[];const payments=d.payment_methods||d.payments_breakdown||[];const statuses=d.repair_status||d.status_breakdown||[];const services=d.revenue_by_service||d.service_revenue||[];return`<div class="topbar"><h1>Reports</h1><div class="topbar-actions"><button class="btn btn-ghost" onclick="exportReport()">Export</button></div></div><div class="filter-bar"><input type="date" value="${state.filters.date_from||''}" onchange="state.filters.date_from=this.value"><input type="date" value="${state.filters.date_to||''}" onchange="state.filters.date_to=this.value"><button class="btn btn-primary btn-sm" onclick="loadReports()">Generate</button></div><div style="display:grid;grid-template-columns:1fr 1fr;gap:20px"><div class="card"><div class="card-header"><h3>Daily Summary</h3></div><table><thead><tr><th>Date</th><th>Sales</th><th>Expenses</th><th>Net</th></tr></thead><tbody>${daily.length?daily.map(d=>`<tr><td>${formatDate(d.date)}</td><td style="color:var(--success)">${formatCurrency(d.sales||d.revenue)}</td><td style="color:var(--danger)">${formatCurrency(d.expenses)}</td><td style="font-weight:600">${formatCurrency((d.sales||d.revenue||0)-(d.expenses||0))}</td></tr>`).join(''):'<tr><td colspan="4" class="empty">No data for selected period</td></tr>'}</tbody></table></div><div class="card"><div class="card-header"><h3>Payment Methods</h3></div>${payments.length?payments.map(p=>`<div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid var(--border)"><span>${esc(p.method||p.name)}</span><span style="font-weight:600">${formatCurrency(p.total||p.amount,p.currency)}</span></div>`).join(''):'<div class="empty">No data</div>'}</div><div class="card"><div class="card-header"><h3>Repair Status Breakdown</h3></div>${statuses.length?statuses.map(s=>`<div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid var(--border)"><span><span class="badge ${STATUS_COLORS[s.status]||''}">${(s.status||s.name||'').replace('_',' ')}</span></span><span style="font-weight:600">${s.count||0}</span></div>`).join(''):'<div class="empty">No data</div>'}</div><div class="card"><div class="card-header"><h3>Revenue by Service</h3></div>${services.length?services.map(s=>`<div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid var(--border)"><span>${esc(s.name||s.service||'-')}</span><span style="font-weight:600">${formatCurrency(s.total||s.revenue,s.currency)}</span></div>`).join(''):'<div class="empty">No data</div>'}</div></div>`;}
function exportReport(){const f=state.filters;let url='/api/reports/export?format=csv&';if(f.date_from)url+=`date_from=${f.date_from}&`;if(f.date_to)url+=`date_to=${f.date_to}`;window.open(url,'_blank');}
async function loadStaff(){const r=await api('/api/staff');if(r.ok){state.staff={data:Array.isArray(r.data)?r.data:r.data.items||[],page:1,total:(Array.isArray(r.data)?r.data.length:r.data.total)||0};}render();}
function renderStaff(){const{data}=state.staff;return`<div class="topbar"><h1>Staff</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showNewStaffModal()">+ Add Staff</button></div></div><div class="card"><div class="table-wrap"><table><thead><tr><th>ID</th><th>Name</th><th>Email</th><th>Phone</th><th>Role</th><th>Active</th><th>Created</th><th>Actions</th></tr></thead><tbody>${data.length?data.map(s=>`<tr><td>#${s.id}</td><td>${esc(s.name)}</td><td>${esc(s.email||'-')}</td><td>${esc(s.phone||'-')}</td><td><span class="badge badge-received">${esc(s.role||'staff')}</span></td><td><span class="badge ${s.active!==false?'badge-active':'badge-inactive'}">${s.active!==false?'Active':'Inactive'}</span></td><td>${formatDate(s.created_at)}</td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showEditStaffModal(${s.id})">Edit</button><button class="btn btn-warning btn-sm" onclick="toggleStaffActive(${s.id},${s.active!==false})">${s.active!==false?'Deactivate':'Activate'}</button></div></td></tr>`).join(''):'<tr><td colspan="8" class="empty">No staff found</td></tr>'}</tbody></table></div></div>`;}
async function showNewStaffModal(){showModal(`<div class="modal-header"><h2>Add Staff</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="createStaff(event)"><div class="form-group"><label>Name *</label><input type="text" id="stfName" required></div><div class="form-row"><div class="form-group"><label>Email *</label><input type="email" id="stfEmail" required></div><div class="form-group"><label>Phone</label><input type="text" id="stfPhone"></div></div><div class="form-group"><label>Role</label><select id="stfRole"><option value="reseller">Reseller</option><option value="retailer">Retailer</option><option value="admin">Admin</option></select></div><div class="form-group"><label style="color:var(--text-muted);font-size:12px">Password will be auto-generated and shown after creation</label></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Add Staff</button></div></form></div>`);}
async function createStaff(e){e.preventDefault();const r=await api('/api/staff',{method:'POST',body:JSON.stringify({name:document.getElementById('stfName').value,email:document.getElementById('stfEmail').value,phone:document.getElementById('stfPhone').value||undefined,role:document.getElementById('stfRole').value})});if(r.ok){const msg=r.data.password?`Staff added. Password: ${r.data.password}`:'Staff added';toast(msg,'success');hideModal();loadStaff();}else toast(r.data.error||'Failed','error');}
async function showEditStaffModal(id){const r=await api(`/api/staff/${id}`);if(!r.ok)return toast('Failed','error');const s=r.data;showModal(`<div class="modal-header"><h2>Edit Staff</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="updateStaff(event,${id})"><div class="form-group"><label>Name *</label><input type="text" id="stfName" value="${esc(s.name)}" required></div><div class="form-row"><div class="form-group"><label>Email *</label><input type="email" id="stfEmail" value="${esc(s.email)}" required></div><div class="form-group"><label>Phone</label><input type="text" id="stfPhone" value="${esc(s.phone||'')}"></div></div><div class="form-group"><label>Role</label><select id="stfRole"><option value="reseller"${s.role==='reseller'?' selected':''}>Reseller</option><option value="retailer"${s.role==='retailer'?' selected':''}>Retailer</option><option value="admin"${s.role==='admin'?' selected':''}>Admin</option></select></div><div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">Update</button></div></form></div>`);}
async function updateStaff(e,id){e.preventDefault();const r=await api(`/api/staff/${id}`,{method:'PUT',body:JSON.stringify({name:document.getElementById('stfName').value,email:document.getElementById('stfEmail').value,phone:document.getElementById('stfPhone').value||undefined,role:document.getElementById('stfRole').value})});if(r.ok){toast('Staff updated','success');hideModal();loadStaff();}else toast(r.data.error||'Failed','error');}
async function toggleStaffActive(id,currentlyActive){const action=currentlyActive?'deactivate':'activate';if(!confirm(`${action} this staff member?`))return;const r=await api(`/api/staff/${id}`,{method:'PUT',body:JSON.stringify({active:!currentlyActive})});if(r.ok){toast(`Staff ${action}d`,'success');loadStaff();}else toast(r.data.error||'Failed','error');}
async function loadSettingsPage(){const r=await api('/api/settings');if(r.ok){state.settings={...state.settings,...r.data};}render();}
function renderSettings(){const s=state.settings;const tab=state.settings_tab||'general';return`<div class="topbar"><h1>Settings</h1></div><div class="tab-bar"><button class="tab-btn${tab==='general'?' active':''}" onclick="state.settings_tab='general';render()">General</button><button class="tab-btn${tab==='brands'?' active':''}" onclick="state.settings_tab='brands';renderCatalogTab('brands')">Brands</button><button class="tab-btn${tab==='models'?' active':''}" onclick="state.settings_tab='models';renderCatalogTab('models')">Models</button><button class="tab-btn${tab==='categories'?' active':''}" onclick="state.settings_tab='categories';renderCatalogTab('categories')">Categories</button><button class="tab-btn${tab==='types'?' active':''}" onclick="state.settings_tab='types';renderCatalogTab('types')">Types</button></div><div id="settingsContent">${tab==='general'?renderSettingsGeneral():''}</div>`;}
function renderSettingsGeneral(){const s=state.settings;return`<div class="card" style="max-width:600px"><form onsubmit="saveSettings(event)"><div class="form-group"><label>Shop Name</label><input type="text" id="setShopName" value="${esc(s.shop_name||'')}"></div><div class="form-group"><label>Address</label><input type="text" id="setAddress" value="${esc(s.shop_address||'')}"></div><div class="form-row"><div class="form-group"><label>Phone</label><input type="text" id="setPhone" value="${esc(s.shop_phone||'')}"></div></div><div class="form-group"><label>Default Currency</label><select id="setCurrency">${CURRENCIES.map(c=>`<option value="${c}"${c===(s.default_currency||'USD')?' selected':''}>${c}</option>`).join('')}</select></div><button type="submit" class="btn btn-primary">Save Settings</button></form></div>`;}
async function saveSettings(e){e.preventDefault();const r=await api('/api/settings',{method:'PUT',body:JSON.stringify({shop_name:document.getElementById('setShopName').value,shop_address:document.getElementById('setAddress').value,shop_phone:document.getElementById('setPhone').value,default_currency:document.getElementById('setCurrency').value})});if(r.ok){toast('Settings saved','success');await loadSettings();render();}else toast(r.data.error||'Failed','error');}
async function renderCatalogTab(type){state.settings_tab=type;const container=document.getElementById('settingsContent');container.innerHTML='<div class="loading"><div class="spinner"></div></div>';if(type==='brands'){const r=await api('/api/catalog/brands');const items=r.ok?(Array.isArray(r.data)?r.data:[]):[];container.innerHTML=`<div class="card"><div class="card-header"><h3>Brands</h3><button class="btn btn-primary btn-sm" onclick="showCatalogModal('brand')">+ Add Brand</button></div><table><thead><tr><th>ID</th><th>Name</th><th>Active</th><th>Actions</th></tr></thead><tbody>${items.length?items.map(b=>`<tr><td>#${b.id}</td><td>${esc(b.name)}</td><td><span class="badge ${b.active!==false?'badge-active':'badge-inactive'}">${b.active!==false?'Active':'Inactive'}</span></td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showCatalogModal('brand',${b.id},'${esc(b.name)}')">Edit</button><button class="btn btn-warning btn-sm" onclick="toggleCatalogActive('brand',${b.id},${b.active!==false})">${b.active!==false?'Deactivate':'Activate'}</button></div></td></tr>`).join(''):'<tr><td colspan="4" class="empty">No brands</td></tr>'}</tbody></table></div>`;}else if(type==='models'){const brandsRes=await api('/api/catalog/brands');const brands=brandsRes.ok?(Array.isArray(brandsRes.data)?brandsRes.data:[]):[];const brandId=state._modelBrand||'';const r=await api(`/api/catalog/models${brandId?'?brand_id='+brandId:''}`);const items=r.ok?(Array.isArray(r.data)?r.data:[]):[];container.innerHTML=`<div class="card"><div class="card-header"><h3>Models</h3><div style="display:flex;gap:8px;align-items:center"><select onchange="state._modelBrand=this.value;renderCatalogTab('models')" style="padding:6px 10px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);font-size:13px"><option value="">All Brands</option>${brands.map(b=>`<option value="${b.id}"${state._modelBrand==b.id?' selected':''}>${esc(b.name)}</option>`).join('')}</select><button class="btn btn-primary btn-sm" onclick="showCatalogModal('model')">+ Add Model</button></div></div><table><thead><tr><th>ID</th><th>Name</th><th>Brand</th><th>Actions</th></tr></thead><tbody>${items.length?items.map(m=>{const brandName=(brands.find(b=>b.id===m.brand_id)||{}).name||'';return`<tr><td>#${m.id}</td><td>${esc(m.name)}</td><td>${esc(brandName)}</td><td><button class="btn btn-ghost btn-sm" onclick="showCatalogModal('model',${m.id},'${esc(m.name)}',${m.brand_id})">Edit</button></td></tr>`;}).join(''):'<tr><td colspan="4" class="empty">No models</td></tr>'}</tbody></table></div>`;}else if(type==='categories'){const r=await api('/api/catalog/categories');const items=r.ok?(Array.isArray(r.data)?r.data:[]):[];container.innerHTML=`<div class="card"><div class="card-header"><h3>Categories</h3><button class="btn btn-primary btn-sm" onclick="showCatalogModal('category')">+ Add Category</button></div><table><thead><tr><th>ID</th><th>Name</th><th>Sort Order</th><th>Actions</th></tr></thead><tbody>${items.length?items.map(c=>`<tr><td>#${c.id}</td><td>${esc(c.name)}</td><td>${c.sort_order||0}</td><td><div style="display:flex;gap:6px"><button class="btn btn-ghost btn-sm" onclick="showCatalogModal('category',${c.id},'${esc(c.name)}')">Edit</button><button class="btn btn-danger btn-sm" onclick="deleteCatalog('category',${c.id})">Delete</button></div></td></tr>`).join(''):'<tr><td colspan="4" class="empty">No categories</td></tr>'}</tbody></table></div>`;}else if(type==='types'){const catsRes=await api('/api/catalog/categories');const cats=catsRes.ok?(Array.isArray(catsRes.data)?catsRes.data:[]):[];const catId=state._typeCat||'';const r=await api(`/api/catalog/types${catId?'?category_id='+catId:''}`);const items=r.ok?(Array.isArray(r.data)?r.data:[]):[];container.innerHTML=`<div class="card"><div class="card-header"><h3>Part Types</h3><div style="display:flex;gap:8px;align-items:center"><select onchange="state._typeCat=this.value;renderCatalogTab('types')" style="padding:6px 10px;background:var(--bg);border:1px solid var(--border);border-radius:6px;color:var(--text);font-size:13px"><option value="">All Categories</option>${cats.map(c=>`<option value="${c.id}"${state._typeCat==c.id?' selected':''}>${esc(c.name)}</option>`).join('')}</select><button class="btn btn-primary btn-sm" onclick="showCatalogModal('type')">+ Add Type</button></div></div><table><thead><tr><th>ID</th><th>Name</th><th>Category</th><th>Actions</th></tr></thead><tbody>${items.length?items.map(t=>{const catName=(cats.find(c=>c.id===t.category_id)||{}).name||'';return`<tr><td>#${t.id}</td><td>${esc(t.name)}</td><td>${esc(catName)}</td><td><button class="btn btn-ghost btn-sm" onclick="showCatalogModal('type',${t.id},'${esc(t.name)}',${t.category_id})">Edit</button></td></tr>`;}).join(''):'<tr><td colspan="4" class="empty">No types</td></tr>'}</tbody></table></div>`;}}
async function showCatalogModal(type,id,currentName,currentParentId){const isEdit=!!id;let brands=[],categories=[];if(type==='model'){const br=await api('/api/catalog/brands');brands=br.ok?(Array.isArray(br.data)?br.data:[]):[]}if(type==='type'){const cr=await api('/api/catalog/categories');categories=cr.ok?(Array.isArray(cr.data)?cr.data:[]):[]}let formHtml='';if(type==='brand'){formHtml=`<div class="form-group"><label>Name *</label><input type="text" id="catName" value="${esc(currentName||'')}" required></div>`;}else if(type==='model'){formHtml=`<div class="form-group"><label>Name *</label><input type="text" id="catName" value="${esc(currentName||'')}" required></div><div class="form-group"><label>Brand *</label><select id="catParent" required><option value="">Select brand</option>${brands.map(b=>`<option value="${b.id}"${currentParentId==b.id?' selected':''}>${esc(b.name)}</option>`).join('')}</select></div>`;}else if(type==='category'){formHtml=`<div class="form-group"><label>Name *</label><input type="text" id="catName" value="${esc(currentName||'')}" required></div>`;}else if(type==='type'){formHtml=`<div class="form-group"><label>Name *</label><input type="text" id="catName" value="${esc(currentName||'')}" required></div><div class="form-group"><label>Category *</label><select id="catParent" required><option value="">Select category</option>${categories.map(c=>`<option value="${c.id}"${currentParentId==c.id?' selected':''}>${esc(c.name)}</option>`).join('')}</select></div>`;}const plural=type+'s';const endpoints={brand:'brands',model:'models',category:'categories',type:'types'};showModal(`<div class="modal-header"><h2>${isEdit?'Edit':'Add'} ${type.charAt(0).toUpperCase()+type.slice(1)}</h2><button class="modal-close" onclick="hideModal()">&times;</button></div><div class="modal-body"><form onsubmit="saveCatalog(event,'${type}',${id||'null'})">${formHtml}<div class="modal-footer"><button type="button" class="btn btn-ghost" onclick="hideModal()">Cancel</button><button type="submit" class="btn btn-primary">${isEdit?'Update':'Create'}</button></div></form></div>`);}
async function saveCatalog(e,type,id){e.preventDefault();const name=document.getElementById('catName').value;const parentEl=document.getElementById('catParent');const endpoints={brand:'brands',model:'models',category:'categories',type:'types'};const body={name};if(type==='model'&&parentEl)body.brand_id=parentEl.value;if(type==='type'&&parentEl)body.category_id=parentEl.value;if(id){const r=await api(`/api/catalog/${endpoints[type]}/${id}`,{method:'PUT',body:JSON.stringify(body)});if(r.ok){toast(`${type} updated`,'success');hideModal();renderCatalogTab(type+'s');}else toast(r.data.error||'Failed','error');}else{const r=await api(`/api/catalog/${endpoints[type]}`,{method:'POST',body:JSON.stringify(body)});if(r.ok){toast(`${type} created`,'success');hideModal();renderCatalogTab(type+'s');}else toast(r.data.error||'Failed','error');}}
async function toggleCatalogActive(type,id,currentlyActive){const endpoints={brand:'brands',model:'models',type:'types'};const r=await api(`/api/catalog/${endpoints[type]}/${id}`,{method:'PUT',body:JSON.stringify({active:!currentlyActive})});if(r.ok){toast(`${type} updated`,'success');renderCatalogTab(type+'s');}else toast(r.data.error||'Failed','error');}
async function deleteCatalog(type,id){if(!confirm('Delete this '+type+'?'))return;const endpoints={category:'categories'};const r=await api(`/api/catalog/${endpoints[type]}/${id}`,{method:'DELETE'});if(r.ok){toast(`${type} deleted`,'success');renderCatalogTab(type+'s');}else toast(r.data.error||'Failed','error');}


// ========== Shops (Intermediate Shops) ==========
async function loadShops(){const r=await api("/api/intermediate-shops");if(r.ok)state.shops=r.data;render();}
function renderShops(){const s=state.shops.data||state.shops;const items=Array.isArray(s)?s:[];return`<div class="topbar"><h1>Market Shops</h1><div class="topbar-actions"><button class="btn btn-primary" onclick="showShopForm()">+ Add Shop</button></div></div><div class="card"><table><thead><tr><th>Name</th><th>Phone</th><th>Address</th><th>Actions</th></tr></thead><tbody>${items.length?items.map(sh=>`<tr><td>${esc(sh.name)}</td><td>${esc(sh.phone)}</td><td>${esc(sh.address)}</td><td><button class="btn btn-sm" onclick="showShopForm(${sh.id})">Edit</button><button class="btn btn-sm btn-danger" onclick="deleteShop(${sh.id})">Delete</button></td></tr>`).join(""):"<tr><td colspan='4'>No shops found</td></tr>"}</tbody></table></div>`;}
function showShopForm(id){const shop=id?state.shops.data.find(s=>s.id===id):null;showModal(`<h2>${id?"Edit":"Add"} Shop</h2><form onsubmit="saveShop(event,${id||""})"><div class="form-group"><label>Name</label><input id="shopName" value="${esc(shop?.name||"")}" required></div><div class="form-group"><label>Phone</label><input id="shopPhone" value="${esc(shop?.phone||"")}"></div><div class="form-group"><label>Address</label><input id="shopAddress" value="${esc(shop?.address||"")}"></div><button type="submit" class="btn btn-primary btn-full">Save</button></form>`);}
async function saveShop(e,id){e.preventDefault();const name=document.getElementById("shopName").value;const phone=document.getElementById("shopPhone").value;const address=document.getElementById("shopAddress").value;const url=id?"/api/intermediate-shops/"+id:"/api/intermediate-shops";const method=id?"PUT":"POST";const r=await api(url,{method,body:JSON.stringify({name,phone,address})});if(r.ok){hideModal();loadShops();toast("Shop saved","success");}else toast(r.data.detail||"Error","error");}
async function deleteShop(id){if(!confirm("Delete this shop?"))return;const r=await api("/api/intermediate-shops/"+id,{method:"DELETE"});if(r.ok){loadShops();toast("Shop deleted","success");}}

// ========== Collections ==========
async function loadCollections(){const r=await api("/api/collections/pending");if(r.ok)state.collections={pending:r.data||[]};render();}
function renderCollections(){const p=state.collections.pending||[];return`<div class="topbar"><h1>Collections</h1></div><div class="card"><div class="card-header"><h3>Pending IR Collections</h3></div><table><thead><tr><th>Repair ID</th><th>Model</th><th>Parts Cost</th><th>Service Fee</th><th>Total</th><th>Created</th></tr></thead><tbody>${p.length?p.map(item=>`<tr><td>#${item.repair_id}</td><td>${esc(item.model)}</td><td>${formatCurrency(item.parts_cost)}</td><td>${formatCurrency(item.service_fee)}</td><td>${formatCurrency(item.total_amount)}</td><td>${formatDate(item.created_at)}</td></tr>`).join(""):"<tr><td colspan='6'>No pending collections</td></tr>"}</tbody></table></div>`;}
